from elasticsearch import Elasticsearch
from elasticsearch.helpers import scan
import json

class DynamicAggregationClient:
    def __init__(self, hosts=['localhost:9200']):
        self.es = Elasticsearch(hosts=hosts)
    
    def execute_dynamic_aggregation(self, index, script_code, params=None, aggregation_type="sum"):
        """
        Execute dynamic script aggregation on Elasticsearch data
        """
        # Prepare the script for Elasticsearch
        script = {
            "script": {
                "source": script_code,
                "lang": "painless"
            }
        }
        
        if params:
            script["script"]["params"] = params
        
        # Build aggregation query
        aggregation_query = {
            "aggs": {
                "dynamic_aggregation": {
                    "scripted_metric": {
                        "init_script": "state.count = 0",
                        "map_script": script,
                        "combine_script": "return state.count",
                        "reduce_script": "double sum = 0.0; for (int i = 0; i < states.length; i++) { sum += states[i]; } return sum;"
                    }
                }
            }
        }
        
        try:
            # Execute the aggregation
            response = self.es.search(
                index=index,
                body=aggregation_query,
                size=0
            )
            
            return response
            
        except Exception as e:
            raise Exception(f"Aggregation execution failed: {str(e)}")

# Example usage function
