# For direct script execution
def execute_script_from_request(req):
    client = DynamicAggregationClient()
    
    # Get script from request
    script_code = req.json.get('script', '')
    
    if not script_code:
        raise ValueError("No script provided")
    
    # Execute the script
    result = client.execute_dynamic_aggregation(
        index=req.json.get('index', 'test'),
        script_code=script_code,
        params=req.json.get('params', {}),
        aggregation_type=req.json.get('aggregation_type', 'sum')
    )
    
    return result